SmartRisk.Table={create({containerId,columns,rows,onAction}){const root=document.getElementById(containerId);root.innerHTML=`<div class="table-wrap"><table class="data-table"><thead><tr>${columns.map(c=>`<th>${c.label}</th>`).join("")}</tr></thead><tbody>${rows.map(r=>`<tr>${columns.map(c=>{const v=r[c.key];if(c.type==="status")return `<td><span class="badge ${v==="Operativa"?"badge-success":"badge-warning"}">${v}</span></td>`;if(c.type==="action")return `<td><button class="icon-btn" data-action="${r.id}">${SmartRisk.Icon.render("eye",17)}</button></td>`;return `<td>${SmartRisk.Utils.escapeHtml(v)}</td>`}).join("")}</tr>`).join("")||`<tr><td colspan="${columns.length}">Sin registros</td></tr>`}</tbody></table></div>`;root.querySelectorAll("[data-action]").forEach(b=>b.onclick=()=>onAction?.(b.dataset.action))}};